// jobworker/manager.go:153-175
 153 | func (jm *JobManager) Output(ctx context.Context, id string) (*OutputBufferReader, error) {
 154 | 	jm.mu.RLock()
 155 | 	job, ok := jm.jobs[id]
 156 | 	jm.mu.RUnlock()
 157 | 
 158 | 	if !ok {
 159 | 		return nil, fmt.Errorf("%w: %s", ErrJobNotFound, id)
 160 | 	}
 161 | 
 162 | 	reader := job.output.NewReader()
 163 | 
 164 | 	// Watcher goroutine exits when the client disconnects (closing the reader) OR buffer drains
 165 | 	// whichever signal comes first, close the reader
 166 | 	// Caller must either call Read() or cancel context to avoid a leak.
 167 | 	go func() {
 168 | 		select {
 169 | 		case <-ctx.Done():
 170 | 		case <-reader.drained:
 171 | 		}
 172 | 		reader.Close()
 173 | 	}()
 174 | 	return reader, nil
 175 | }
